/**
 * CLIController - Developer/Admin Command Line Interface
 *
 * Provides a command-line interface within the chat prompt for developers
 * and administrators to configure the SaaS client behavior.
 *
 * Commands are prefixed with "::" and only available to users with role > 50.
 *
 * Usage:
 *   ::help - Show available commands
 *   ::clear - Clear chat history
 *   ::debug on - Enable debug mode
 *   ::feature list - List feature flags
 *   ::model status - Show LLM model status
 *
 * Singleton pattern - use CLIController.method() to access
 */

import PubSub from 'pubsub-js';
import AppBroadcast from '../../../../shared/appBroadcast.js';
import { FEATURE_FLAGS } from '../../../../shared/featureFlags.js';
import { EntityClasses, getRoleByName } from '../../../../packages/shared/src/metadata/entityClasses.js';

class CLIController {
  // Minimum role value required for CLI access
  static MIN_ROLE_VALUE = 50;

  // Available commands
  static COMMANDS = {
    help: 'Show available commands',
    clear: 'Clear chat canvas',
    debug: 'Toggle debug mode (::debug on|off)',
    version: 'Show application version',
    feature: 'Feature flag operations (::feature list|get|set)',
    model: 'LLM model operations (::model status|download|clear)',
    reload: 'Reload the page',
    export: 'Export chat history as JSON',
    theme: 'Toggle theme (::theme dark|light)',
    auth: 'Show authentication status'
  };

  /**
   * Check if user has CLI access based on role
   * @param {Object} entity - User entity from AuthController
   * @returns {boolean}
   */
  static hasAccess(entity) {
    if (!entity || !entity.class) {
      return false;
    }

    // Get role value from class name
    let roleValue = 0;

    if (typeof entity.class === 'string') {
      // class is a string like "admin_root_role"
      const role = getRoleByName(entity.class);
      roleValue = role ? role.value : 0;
    } else if (typeof entity.class === 'object' && entity.class.value !== undefined) {
      // class is already an object with value
      roleValue = entity.class.value;
    }

    console.log(`[CLIController] Role check: ${entity.class} → value: ${roleValue}`);
    return roleValue >= this.MIN_ROLE_VALUE;
  }

  /**
   * Process CLI command
   * @param {string} input - Full command input (including ::)
   * @param {Object} entity - User entity from AuthController
   * @returns {Object} Response object with message and action
   */
  static async process(input, entity) {
    // Check access
    if (!this.hasAccess(entity)) {
      return {
        error: true,
        message: '⛔ **Access Denied**\n\nCLI commands require admin privileges (role ≥ 50).'
      };
    }

    // Remove :: prefix and parse command
    const command = input.slice(2).trim();
    const [cmd, ...args] = command.split(/\s+/);

    console.log('[CLIController] Processing command:', cmd, 'Args:', args);

    // Route to command handler
    switch (cmd.toLowerCase()) {
      case 'help':
        return this.cmdHelp();
      case 'clear':
        return this.cmdClear();
      case 'debug':
        return this.cmdDebug(args);
      case 'version':
        return this.cmdVersion();
      case 'feature':
        return this.cmdFeature(args);
      case 'model':
        return this.cmdModel(args);
      case 'reload':
        return this.cmdReload();
      case 'export':
        return this.cmdExport();
      case 'theme':
        return this.cmdTheme(args);
      case 'auth':
        return this.cmdAuth(entity);
      default:
        return {
          error: true,
          message: `❌ **Unknown command:** \`${cmd}\`\n\nType \`::help\` for available commands.`
        };
    }
  }

  /**
   * Display help
   */
  static cmdHelp() {
    let help = '📖 **CLI Commands**\n\n';
    help += 'Available commands (prefix with `::`)\n\n';

    for (const [cmd, desc] of Object.entries(this.COMMANDS)) {
      help += `• \`::${cmd}\` - ${desc}\n`;
    }

    help += '\n**Examples:**\n';
    help += '• `::debug on` - Enable debug logging\n';
    help += '• `::feature list` - Show all feature flags\n';
    help += '• `::model status` - Check LLM model status\n';

    return { message: help };
  }

  /**
   * Clear chat canvas
   */
  static cmdClear() {
    const chatMessages = document.getElementById('chat-messages');
    if (chatMessages) {
      chatMessages.innerHTML = '';
      return { message: '✅ Chat canvas cleared' };
    }
    return { error: true, message: '❌ Failed to clear canvas' };
  }

  /**
   * Toggle debug mode
   */
  static cmdDebug(args) {
    const action = args[0]?.toLowerCase();

    if (!action || !['on', 'off'].includes(action)) {
      const currentState = localStorage.getItem('debug_mode') === 'true';
      return {
        message: `🐛 **Debug Mode**\n\nCurrent state: \`${currentState ? 'ON' : 'OFF'}\`\n\nUsage: \`::debug on|off\``
      };
    }

    const enable = action === 'on';
    localStorage.setItem('debug_mode', enable);

    return {
      message: `🐛 Debug mode ${enable ? '**enabled**' : '**disabled**'}`
    };
  }

  /**
   * Show version
   */
  static cmdVersion() {
    return {
      message: `ℹ️ **StreamSyncEngage SaaS Client**\n\nVersion: 1.0.0\nBuild: ${import.meta.env.MODE}\nNode Env: ${import.meta.env.MODE}`
    };
  }

  /**
   * Feature flag operations
   */
  static cmdFeature(args) {
    const action = args[0]?.toLowerCase();

    if (!action) {
      return {
        message: '🚩 **Feature Flags**\n\nUsage:\n• `::feature list` - List all flags\n• `::feature get <name>` - Get flag value\n• `::feature set <name> <value>` - Set flag value'
      };
    }

    switch (action) {
      case 'list': {
        let msg = '🚩 **Feature Flags**\n\n';
        const flags = Object.entries(FEATURE_FLAGS).slice(0, 20); // Show first 20
        for (const [key, value] of flags) {
          msg += `• \`${key}\`: \`${value}\`\n`;
        }
        msg += `\n*Showing 20 of ${Object.keys(FEATURE_FLAGS).length} flags*`;
        return { message: msg };
      }

      case 'get': {
        const flagName = args[1];
        if (!flagName) {
          return { error: true, message: '❌ Flag name required: `::feature get <name>`' };
        }
        const value = FEATURE_FLAGS[flagName];
        if (value === undefined) {
          return { error: true, message: `❌ Flag not found: \`${flagName}\`` };
        }
        return { message: `🚩 \`${flagName}\` = \`${value}\`` };
      }

      case 'set': {
        return {
          message: '⚠️ **Feature flag modification**\n\nSetting flags dynamically is not yet implemented.\nFlags are loaded from `featureFlags.js`.'
        };
      }

      default:
        return { error: true, message: `❌ Unknown action: \`${action}\`` };
    }
  }

  /**
   * LLM model operations
   */
  static cmdModel(args) {
    const action = args[0]?.toLowerCase();

    if (!action) {
      return {
        message: '🤖 **LLM Model Operations**\n\nUsage:\n• `::model status` - Show model status\n• `::model download` - Download model\n• `::model clear` - Clear model cache'
      };
    }

    switch (action) {
      case 'status': {
        if (!window.LLMController) {
          return { error: true, message: '❌ LLMController not available' };
        }

        const status = window.LLMController.getStatus();
        let msg = '🤖 **LLM Model Status**\n\n';
        msg += `• Model: \`${status.modelId}\`\n`;
        msg += `• Loaded: \`${status.isLoaded ? 'YES' : 'NO'}\`\n`;
        msg += `• Cached: \`${status.isCached ? 'YES' : 'NO'}\`\n`;
        msg += `• Generating: \`${status.isGenerating ? 'YES' : 'NO'}\`\n`;
        msg += `• Message Count: \`${status.messageCount}\`\n`;

        return { message: msg };
      }

      case 'download': {
        if (!window.LLMController) {
          return { error: true, message: '❌ LLMController not available' };
        }

        // Trigger download
        window.LLMController.loadModel();
        return { message: '⏳ Starting model download...' };
      }

      case 'clear': {
        return {
          message: '⚠️ **Clear Model Cache**\n\nClearing browser cache requires manual action:\n1. Open DevTools (F12)\n2. Application → Storage → Cache Storage\n3. Delete `webllm/model`'
        };
      }

      default:
        return { error: true, message: `❌ Unknown action: \`${action}\`` };
    }
  }

  /**
   * Reload page
   */
  static cmdReload() {
    setTimeout(() => {
      window.location.reload();
    }, 500);
    return { message: '🔄 Reloading page...' };
  }

  /**
   * Export chat history
   */
  static cmdExport() {
    const chatMessages = document.getElementById('chat-messages');
    if (!chatMessages) {
      return { error: true, message: '❌ Chat canvas not found' };
    }

    const bubbles = Array.from(chatMessages.children);
    const history = bubbles.map(bubble => ({
      type: bubble.tagName.toLowerCase().includes('prompt') ? 'user' : 'assistant',
      message: bubble.getAttribute('message'),
      timestamp: bubble.getAttribute('timestamp')
    }));

    const json = JSON.stringify(history, null, 2);
    const blob = new Blob([json], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `chat-export-${Date.now()}.json`;
    a.click();
    URL.revokeObjectURL(url);

    return { message: `✅ Exported ${history.length} messages` };
  }

  /**
   * Toggle theme
   */
  static cmdTheme(args) {
    const theme = args[0]?.toLowerCase();

    if (!theme || !['dark', 'light'].includes(theme)) {
      return {
        message: '🎨 **Theme Toggle**\n\nUsage: `::theme dark|light`'
      };
    }

    // Store in localStorage for persistence
    localStorage.setItem('theme', theme);

    return {
      message: `🎨 Theme set to **${theme}**\n\n⚠️ Theme switching not yet implemented in UI.`
    };
  }

  /**
   * Show authentication status
   */
  static cmdAuth(entity) {
    if (!entity) {
      return { error: true, message: '❌ Not authenticated' };
    }

    // Get role details
    let roleDesc = 'Unknown';
    let roleValue = 0;

    if (typeof entity.class === 'string') {
      const role = getRoleByName(entity.class);
      if (role) {
        roleDesc = role.desc;
        roleValue = role.value;
      }
    } else if (typeof entity.class === 'object') {
      roleDesc = entity.class.desc || 'Unknown';
      roleValue = entity.class.value || 0;
    }

    let msg = '🔐 **Authentication Status**\n\n';
    msg += `• Email: \`${entity.email}\`\n`;
    msg += `• Name: \`${entity.first} ${entity.last}\`\n`;
    msg += `• Role: \`${entity.class}\`\n`;
    msg += `• Role Description: \`${roleDesc}\`\n`;
    msg += `• Role Value: \`${roleValue}\`\n`;
    msg += `• Company: \`${entity.company || 'N/A'}\`\n`;
    msg += `• Status: \`${entity.status || 'Unknown'}\`\n`;

    return { message: msg };
  }
}

export default CLIController;
