/**
 * LLMController - WebLLM Integration Service
 *
 * Manages local Large Language Model (WebLLM) functionality:
 * - Model download and caching
 * - Initialization and engine management
 * - Streaming chat completions
 * - Progress tracking and error handling
 *
 * Singleton pattern - use LLMController.method() to access
 *
 * PubSub Integration:
 * - Publishes to: LLM_STATUS, LLM_COMPLETE, LLM_ERROR, LLM_RESPONSE
 * - Subscribes to: LLM_DO_DOWNLOAD, LLM_PROMPT, LLM_CANCEL
 */

import PubSub from 'pubsub-js';
import AppBroadcast from '../../../../shared/appBroadcast.js';

class LLMController {
  // Singleton state
  static engine = null;
  static webllm = null;
  static isInitialized = false;
  static currentModel = null;
  static isGenerating = false;
  static isModelCached = false; // Simple boolean - we only use one model

  // Single model for this application
  static DEFAULT_MODEL = 'Llama-3.2-1B-Instruct-q4f32_1-MLC';

  // Message history (system prompt + conversation)
  static messages = [
    { role: 'system', content: 'You are a helpful AI assistant running locally in the browser using WebLLM. Be concise and helpful.' }
  ];

  /**
   * Initialize the WebLLM module and engine
   * Must be called before any other operations
   */
  static async initialize() {
    if (this.isInitialized) {
      console.log('[LLMController] Already initialized');
      return true;
    }

    console.log('[LLMController] Initializing WebLLM module...');

    try {
      // Check WebGPU support
      if (!navigator.gpu) {
        throw new Error('WebGPU is not available. Please use a supported browser (Chrome 113+, Edge 113+).');
      }
      console.log('[LLMController] WebGPU detected');

      // Load WebLLM module from CDN
      this.webllm = await import('https://esm.run/@mlc-ai/web-llm');
      console.log('[LLMController] WebLLM module loaded');

      // Verify MLCEngine exists
      if (!this.webllm || !this.webllm.MLCEngine) {
        throw new Error('MLCEngine not found in WebLLM module');
      }

      // Create engine instance
      this.engine = new this.webllm.MLCEngine();
      console.log('[LLMController] MLCEngine created');

      // Set progress callback to publish status updates
      this.engine.setInitProgressCallback((report) => {
        this.handleInitProgress(report);
      });

      // Check if our model is cached
      this.isModelCached = await this.checkModelCache();

      // Mark as initialized BEFORE auto-load (so downloadModel works)
      this.isInitialized = true;
      console.log('[LLMController] Engine initialized, attempting auto-load...');

      // Auto-load cached model if found
      await this.autoLoadCachedModel();

      console.log('[LLMController] Initialization complete');
      return true;

    } catch (error) {
      console.error('[LLMController] Initialization failed:', error);
      PubSub.publish(AppBroadcast.LLM_ERROR, {
        error: error.message,
        phase: 'initialization'
      });
      return false;
    }
  }

  /**
   * Check if our single model is cached
   * @returns {boolean} True if model files found in cache
   */
  static async checkModelCache() {
    console.log(`[LLMController] Checking cache for model: ${this.DEFAULT_MODEL}`);

    try {
      // Check Cache API directly - look for webllm/model cache
      const cacheNames = await caches.keys();
      const webllmModelCache = cacheNames.find(name => name.includes('webllm/model'));

      if (!webllmModelCache) {
        console.log('[LLMController] No WebLLM model cache found');
        return false;
      }

      const cache = await caches.open(webllmModelCache);
      const cachedRequests = await cache.keys();
      const modelFiles = cachedRequests.filter(req =>
        req.url.includes(this.DEFAULT_MODEL) || req.url.includes('Llama-3.2-1B')
      );

      const isCached = modelFiles.length > 0;
      console.log(`[LLMController] Model cached: ${isCached} (${modelFiles.length} files)`);
      return isCached;

    } catch (err) {
      console.warn(`[LLMController] Cache check failed:`, err.message);
      return false;
    }
  }

  /**
   * Auto-load cached model on initialization
   * If model is not cached, automatically download it
   */
  static async autoLoadCachedModel() {
    try {
      if (this.isModelCached) {
        console.log(`[LLMController] Loading cached model: ${this.DEFAULT_MODEL}`);
      } else {
        console.log(`[LLMController] No cached model found - starting download: ${this.DEFAULT_MODEL}`);
      }

      await this.loadModel();
      console.log('[LLMController] Model ready');
    } catch (error) {
      console.error('[LLMController] Auto-load failed:', error);
      // Don't throw - non-critical error
    }
  }

  /**
   * Load the model (download if not cached, or load from cache)
   * This is the only model-loading method - simplified for single-model use
   */
  static async loadModel() {
    if (!this.isInitialized) {
      console.error('[LLMController] Cannot load model: not initialized');
      PubSub.publish(AppBroadcast.LLM_ERROR, {
        error: 'LLMController not initialized',
        modelId: this.DEFAULT_MODEL
      });
      return false;
    }

    const wasCached = this.isModelCached;
    console.log(`[LLMController] Loading model: ${this.DEFAULT_MODEL} (cached: ${wasCached})`);

    try {
      // Reload engine with our model (downloads if needed, or loads from cache)
      const chatConfig = {
        temperature: 0.7,
        top_p: 0.95
      };

      await this.engine.reload(this.DEFAULT_MODEL, chatConfig);

      this.currentModel = this.DEFAULT_MODEL;
      this.isModelCached = true;

      console.log(`[LLMController] Model loaded successfully: ${this.DEFAULT_MODEL}`);

      // Publish completion event
      PubSub.publish(AppBroadcast.LLM_COMPLETE, {
        modelId: this.DEFAULT_MODEL,
        cached: wasCached
      });

      return true;

    } catch (error) {
      console.error(`[LLMController] Failed to load model:`, error);
      PubSub.publish(AppBroadcast.LLM_ERROR, {
        error: error.message,
        modelId: this.DEFAULT_MODEL,
        phase: 'download'
      });
      return false;
    }
  }

  /**
   * Handle initialization progress callback
   * Publishes progress updates via PubSub
   */
  static handleInitProgress(report) {
    const progressPercent = (report.progress * 100).toFixed(1);
    let progressText = report.text;

    // Format progress text
    if (progressPercent > 0 || !report.text.includes('Loading model from cache')) {
      progressText = `${progressPercent}% - ${report.text}`;
    }

    console.log(`[LLMController] Progress: ${progressText}`);

    // Publish status update
    PubSub.publish(AppBroadcast.LLM_STATUS, {
      progress: report.progress,
      progressPercent: parseFloat(progressPercent),
      text: progressText,
      modelId: this.currentModel || this.DEFAULT_MODEL
    });
  }

  /**
   * Send a chat message and get streaming response
   * @param {string} userMessage - User's message
   */
  static async chat(userMessage) {
    if (!this.currentModel) {
      console.error('[LLMController] No model loaded - still downloading or initialization failed');
      PubSub.publish(AppBroadcast.LLM_ERROR, {
        error: 'AI model is still loading. Please wait a moment and try again.',
        phase: 'chat'
      });
      return;
    }

    if (this.isGenerating) {
      console.warn('[LLMController] Already generating response');
      return;
    }

    console.log(`[LLMController] Processing chat message: "${userMessage}"`);

    // Add user message to history
    const userMsg = { role: 'user', content: userMessage };
    this.messages.push(userMsg);

    this.isGenerating = true;
    let currentResponse = '';

    try {
      // Create streaming completion
      const completion = await this.engine.chat.completions.create({
        stream: true,
        messages: this.messages,
        stream_options: { include_usage: true }
      });

      // Process stream
      for await (const chunk of completion) {
        const deltaContent = chunk.choices[0]?.delta?.content;

        if (deltaContent) {
          currentResponse += deltaContent;

          // Publish response chunk
          PubSub.publish(AppBroadcast.LLM_RESPONSE, {
            content: deltaContent,
            fullContent: currentResponse,
            done: false
          });
        }

        // Capture usage stats
        if (chunk.usage) {
          console.log('[LLMController] Usage stats:', chunk.usage);
        }
      }

      // Add assistant response to history
      this.messages.push({ role: 'assistant', content: currentResponse });

      // Publish completion
      PubSub.publish(AppBroadcast.LLM_RESPONSE, {
        content: '',
        fullContent: currentResponse,
        done: true
      });

      console.log(`[LLMController] Response complete (${currentResponse.length} chars)`);

    } catch (error) {
      console.error('[LLMController] Chat error:', error);
      PubSub.publish(AppBroadcast.LLM_ERROR, {
        error: error.message,
        phase: 'chat'
      });
    } finally {
      this.isGenerating = false;
    }
  }

  /**
   * Cancel ongoing generation
   */
  static cancelGeneration() {
    if (!this.isGenerating || !this.engine) {
      console.warn('[LLMController] Nothing to cancel');
      return;
    }

    console.log('[LLMController] Cancelling generation...');

    try {
      this.engine.interruptGenerate();
      this.isGenerating = false;
      console.log('[LLMController] Generation cancelled');
    } catch (error) {
      console.error('[LLMController] Cancel failed:', error);
    }
  }

  /**
   * Get current model status
   * @returns {Object} Model status details
   */
  static getStatus() {
    return {
      modelId: this.DEFAULT_MODEL,
      isLoaded: !!this.currentModel,
      isCached: this.isModelCached,
      isGenerating: this.isGenerating,
      messageCount: this.messages.length
    };
  }

  /**
   * Reset conversation history
   */
  static resetConversation() {
    this.messages = [
      { role: 'system', content: 'You are a helpful AI assistant running locally in the browser using WebLLM. Be concise and helpful.' }
    ];
    console.log('[LLMController] Conversation reset');
  }
}

export default LLMController;
