/**
 * Get feature flag value with optional override from environment variables
 *
 * @param {string} flagName - Name of the feature flag
 * @param {*} defaultValue - Default value if not found
 * @returns {*} Feature flag value
 *
 * @example
 * const sessionKey = getFlag('FF_SSE_LS_SESSION_USER', 'session_user');
 */
function getFlag(flagName, defaultValue = null) {
  // Check if flag exists in registry
  if (flagName in FEATURE_FLAGS) {
    return FEATURE_FLAGS[flagName];
  }

  // Check environment variables (Node.js)
  if (typeof process !== 'undefined' && process.env && process.env[flagName]) {
    const envValue = process.env[flagName];

    // Parse boolean strings
    if (envValue === 'true') return true;
    if (envValue === 'false') return false;

    // Parse numeric strings
    if (!isNaN(envValue)) return Number(envValue);

    return envValue;
  }

  // Check Vite environment variables (Frontend)
  if (typeof import.meta !== 'undefined' && import.meta.env && import.meta.env[flagName]) {
    const envValue = import.meta.env[flagName];

    // Parse boolean strings
    if (envValue === 'true') return true;
    if (envValue === 'false') return false;

    // Parse numeric strings
    if (!isNaN(envValue)) return Number(envValue);

    return envValue;
  }

  return defaultValue;
}

/**
 * Check if feature flag is enabled (boolean flags only)
 *
 * @param {string} flagName - Name of the feature flag
 * @returns {boolean} True if enabled, false otherwise
 *
 * @example
 * if (isEnabled('FF_SSE_FEATURE_SIGNUP_ENABLED')) {
 *   // Show signup button
 * }
 */
function isEnabled(flagName) {
  return getFlag(flagName, false) === true;
}

/**
 * Get all feature flags as a plain object
 *
 * @returns {Object} All feature flags
 */
function getAllFlags() {
  return { ...FEATURE_FLAGS };
}

/**
 * Export for both CommonJS (Node.js) and ES Modules (Frontend)
 */
// ES Modules (default)
export { FEATURE_FLAGS, getFlag, isEnabled, getAllFlags };

// CommonJS (Node.js)
if (typeof module !== 'undefined' && module.exports) {
  module.exports = {
    FEATURE_FLAGS,
    getFlag,
    isEnabled,
    getAllFlags
  };
}
