router.on('/', () => {
  console.log('[Router] Route: /');
  PubSub.publish(AppBroadcast.ROUTE_NAV_BEFORE, { route: 'splash' });

  // Load splash route
  import('./routes/splash-route.js')
    .then(module => {
      const container = document.getElementById('app');
      container.innerHTML = module.render();
      if (module.init) module.init();
      PubSub.publish(AppBroadcast.ROUTE_NAV_AFTER, { route: 'splash' });
    })
    .catch(err => {
      console.error('[Router] Error loading splash route:', err);
      PubSub.publish(AppBroadcast.ROUTE_NAV_ERROR, { route: 'splash', error: err });
    });
});

