// ============================================
// Initialize Application
// ============================================

// Wait for Neodigm 55 library to load, then initialize
// Note: We need to wait for both DOM and external scripts
function waitForNeodigm() {
  console.log('[App] Waiting for Neodigm 55 library...');

  let attempts = 0;
  const maxAttempts = 100; // 10 seconds (100 * 100ms)

  const checkMvvLegit = setInterval(() => {
    attempts++;

    // Log debug info every 10 attempts (1 second)
    if (attempts % 10 === 0) {
      console.log(`[App] Still waiting... attempt ${attempts}/100`, {
        mvvLegitExists: typeof mvvLegit !== 'undefined',
        neodigmLoaded: window.__neodigmLoaded
      });
    }

    if (typeof mvvLegit !== 'undefined') {
      console.log(`[App] Neodigm 55 loaded after ${attempts * 100}ms`);
      clearInterval(checkMvvLegit);
      initializeApp();
    } else if (attempts >= maxAttempts) {
      clearInterval(checkMvvLegit);
      console.error('[App] Failed to load Neodigm 55 library after 10 seconds');
      console.error('[App] Check browser console for CORS or network errors');

      // Show error in UI
      document.getElementById('app').innerHTML = `
        <div style="padding: 2rem; text-align: center; font-family: sans-serif;">
          <h2 style="color: #f44336;">Failed to Load Authentication Library</h2>
          <p>The Neodigm 55 library could not be loaded from the CDN.</p>
          <p>Please check your internet connection and try refreshing the page.</p>
          <button onclick="location.reload()" style="padding: 10px 20px; font-size: 1rem; cursor: pointer;">
            Refresh Page
          </button>
        </div>
      `;

      PubSub.publish(AppBroadcast.APP_ERROR, {
        message: 'Failed to load authentication library'
      });
    }
  }, 100);
}

// Start waiting as soon as possible
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', waitForNeodigm);
} else {
  // DOM already loaded
  waitForNeodigm();
}

/**
 * Initialize application after Neodigm 55 is loaded
 */
async function initializeApp() {
  console.log('[App] Neodigm 55 loaded, initializing...');

  // Initialize event system
  initAppEvents();

  // Initialize i18n Controller (must be before route navigation)
  I18nController.initialize();
  console.log('[App] I18n Controller initialized');

  // Initialize LLMController (WebLLM for local AI)
  // This runs in background - doesn't block app startup
  LLMController.initialize()
    .then((success) => {
      if (success) {
        console.log('[App] LLM Controller initialized successfully');
      } else {
        console.warn('[App] LLM Controller initialization failed (non-critical)');
      }
    })
    .catch((err) => {
      console.error('[App] LLM Controller initialization error:', err);
    });

  // Initialize AuthController (replaces direct mvvLegit initialization)
  const authInitialized = await AuthController.init({
    BASE_URL: import.meta.env.VITE_API_BASE_URL || 'http://localhost:3333',
    navigateFunction: (routePath) => {
      console.log('[AuthController] Navigation requested:', routePath);
      navigateToRoute(routePath);
    }
  });

  if (!authInitialized) {
    console.error('[App] AuthController initialization failed');
    return;
  }

  // Note: AuthController already handles mvvLegit state changes internally
  // The APP_AUTH event will be published by AuthController's state callback if needed

  // Load persisted session user from localStorage (AuthController handles this)
  const sessionUser = AuthController.getEntity();
  if (sessionUser) {
    console.log('[App] Session restored for:', sessionUser.email);
    // Publish entity loaded event for other components to use
    PubSub.publish(AppBroadcast.APP_USER_LOADED, { entity: sessionUser });
  }

  // Publish app ready event
  PubSub.publish(AppBroadcast.APP_READY, {
    timestamp: new Date().toISOString(),
    sessionUser
  });

  // Resolve routes
  router.resolve();

  // Expose controllers globally for debugging and language switching
  window.AuthController = AuthController;
  window.I18nController = I18nController;
  window.LLMController = LLMController;
  console.log('[App] StreamSyncEngage client initialized (AuthController, I18nController, LLMController available globally)');
}

// Subscribe to route navigation events to trigger i18n refresh
PubSub.subscribe(AppBroadcast.ROUTE_NAV_AFTER, (_msg, data) => {
  // Trigger i18n refresh after route navigation completes
  if (typeof I18nController !== 'undefined' && I18nController.refresh) {
    setTimeout(() => {
      I18nController.refresh();
    }, 100); // Small delay to ensure DOM is updated
  }
});
