export function init() {
  console.log('[HomeRoute] Initialized');

  // Navigation events are now handled globally by the WebComponentBridge in app_events.js
  // The bridge listens to all 'nav-select' events and publishes to M5T_PRIMARY_NAV_TAP
  // Route-specific logic is handled by PubSub subscribers in app_events.js

  // No scroll manipulation needed - column-reverse handles bottom-anchoring automatically!

  // CONVERSATION events are handled globally in app_events.js
  // Canvas population happens via PubSub -> app_events.js -> addChatBubbleToCanvas()

  // Subscribe to CANVAS.DO.SCROLL event
  PubSub.subscribe(AppBroadcast.CANVAS_DO_SCROLL, (msg, data) => {
    console.log('[HomeRoute] CANVAS.DO.SCROLL triggered');
    scrollToBottomOfCanvas();
  });

  // Subscribe to LLM_STATUS for download progress
  PubSub.subscribe(AppBroadcast.LLM_STATUS, (msg, data) => {
    console.log('[HomeRoute] LLM_STATUS:', data);

    if (data && data.text) {
      // Show progress as streaming assistant message
      const progressMessage = `🔄 ${data.text}`;

      // Use streaming flag to update the same bubble
      PubSub.publish(AppBroadcast.CONVERSATION_RESPONSE_CANVAS, {
        message: progressMessage,
        timestamp: new Date().toLocaleTimeString('en-US', {
          hour: 'numeric',
          minute: '2-digit'
        }),
        streaming: true  // This will update existing bubble instead of creating new one
      });
    }
  });
}

/**
 * Smoothly scroll to bottom of chat canvas
 * Uses 80ms delay for smooth animation
 *
 * Note: With column-reverse, scrolling to 0 shows the latest messages at the bottom
 */
function scrollToBottomOfCanvas() {
  setTimeout(() => {
    const chatMessages = document.getElementById('chat-messages');
    if (chatMessages) {
      // With column-reverse, scroll to 0 to show latest messages
      chatMessages.scrollTo({
        top: 0,
        behavior: 'smooth'
      });
      console.log('[HomeRoute] Scrolled chat-messages to bottom (top: 0 with column-reverse)');
    } else {
      console.warn('[HomeRoute] chat-messages element not found');
    }
  }, 80);
}

/**
 * Add chat bubble via PubSub (public API)
 * Publishes to CONVERSATION topics which are handled by subscribers
 *
 * @param {string} message - Message text
 * @param {string} type - 'user' or 'assistant'
 * @param {string} target - Where to send: 'canvas', 'agent', 'agent_canvas', 'stage'
 */
function addChatBubble(message, type = 'user', target = 'canvas') {
  const timestamp = new Date().toLocaleTimeString('en-US', {
    hour: 'numeric',
    minute: '2-digit'
  });

  const data = { message, timestamp };

  if (type === 'user' || type === 'prompt') {
    // Publish user prompt
    switch(target.toUpperCase()) {
      case 'CANVAS':
        PubSub.publish(AppBroadcast.CONVERSATION_PROMPT_CANVAS, data);
        break;
      case 'AGENT':
        PubSub.publish(AppBroadcast.CONVERSATION_PROMPT_AGENT, data);
        break;
      case 'AGENT_CANVAS':
        PubSub.publish(AppBroadcast.CONVERSATION_PROMPT_AGENT_CANVAS, data);
        break;
      case 'STAGE':
        PubSub.publish(AppBroadcast.CONVERSATION_PROMPT_STAGE, data);
        break;
      default:
        PubSub.publish(AppBroadcast.CONVERSATION_PROMPT_CANVAS, data);
    }
  } else {
    // Publish assistant response
    switch(target.toUpperCase()) {
      case 'CANVAS':
        PubSub.publish(AppBroadcast.CONVERSATION_RESPONSE_CANVAS, data);
        break;
      case 'WORKFLOW':
        PubSub.publish(AppBroadcast.CONVERSATION_RESPONSE_WORKFLOW, data);
        break;
      default:
        PubSub.publish(AppBroadcast.CONVERSATION_RESPONSE_CANVAS, data);
    }
  }
}

