/**
 * Generate random chat bubbles for testing scroll behavior
 * Call from console: window.generateRandomBubbles(20)
 *
 * @param {number} count - Number of bubbles to generate
 * @param {number} delay - Delay between bubbles in ms (default: 500)
 */
function generateRandomBubbles(count = 10, delay = 500) {
  const userMessages = [
    "Hey, how's it going?",
    "Can you help me with something?",
    "What's the weather like today?",
    "I need assistance with my account",
    "Tell me a joke!",
    "How do I reset my password?",
    "What are your hours?",
    "Thanks for your help!",
    "I have a question about billing",
    "Can you explain this feature?",
    "How do I upgrade my plan?",
    "What's new in the latest update?",
    "I'm having trouble logging in",
    "Where can I find the settings?",
    "How secure is my data?",
    "Do you offer customer support?",
    "What payment methods do you accept?",
    "Can I cancel my subscription?",
    "How do I export my data?",
    "Is there a mobile app?"
  ];

  const assistantMessages = [
    "I'm doing great! How can I help you today?",
    "Of course! I'd be happy to assist you.",
    "Let me check that for you...",
    "Here's what I found:",
    "That's a great question!",
    "I can help you with that.",
    "Let me walk you through the steps.",
    "You're very welcome!",
    "I understand your concern. Let me explain...",
    "That feature is located in the settings menu.",
    "Your account is fully secured with encryption.",
    "We're available 24/7 to help you!",
    "We accept all major credit cards and PayPal.",
    "You can upgrade anytime from your account settings.",
    "The latest update includes several new features!",
    "Try resetting your password using the forgot password link.",
    "Your data is encrypted and stored securely.",
    "Yes! Our mobile app is available for iOS and Android.",
    "You can export your data from the account settings.",
    "Absolutely! You can cancel anytime with no fees."
  ];

  let counter = 0;

  const interval = setInterval(() => {
    if (counter >= count) {
      clearInterval(interval);
      console.log(`[Test] Generated ${count} random bubbles`);
      return;
    }

    // Randomly choose user or assistant
    const isUser = Math.random() > 0.5;
    const type = isUser ? 'user' : 'assistant';

    // Pick random message
    const messages = isUser ? userMessages : assistantMessages;
    const message = messages[Math.floor(Math.random() * messages.length)];

    // Add bubble
    addChatBubble(message, type);

    counter++;
    console.log(`[Test] Added bubble ${counter}/${count} (${type})`);
  }, delay);
}

/**
 * Continuous bubble generation (runs until stopped)
 * Call from console: window.startBubbleStream()
 * Stop with: window.stopBubbleStream()
 */
let bubbleStreamInterval = null;

function startBubbleStream(delayMs = 1000) {
  if (bubbleStreamInterval) {
    console.log('[Test] Bubble stream already running. Stop it first with stopBubbleStream()');
    return;
  }

  console.log('[Test] Starting continuous bubble stream...');

  bubbleStreamInterval = setInterval(() => {
    const isUser = Math.random() > 0.5;
    const messages = isUser
      ? ["Quick message!", "Another one!", "Test bubble", "Hello there!", "Random user text"]
      : ["Response here", "Got it!", "Processing...", "Here's the answer", "Understood!"];

    const message = messages[Math.floor(Math.random() * messages.length)];
    addChatBubble(message, isUser ? 'user' : 'assistant');
  }, delayMs);
}

function stopBubbleStream() {
  if (bubbleStreamInterval) {
    clearInterval(bubbleStreamInterval);
    bubbleStreamInterval = null;
    console.log('[Test] Bubble stream stopped');
  } else {
    console.log('[Test] No bubble stream running');
  }
}

/**
 * Clear all chat bubbles
 */
function clearAllBubbles() {
  const chatMessages = document.getElementById('chat-messages');
  if (chatMessages) {
    chatMessages.innerHTML = '';
    console.log('[Test] All bubbles cleared');
  }
}

// Expose test functions globally
window.addChatBubble = addChatBubble;
window.generateRandomBubbles = generateRandomBubbles;
window.startBubbleStream = startBubbleStream;
window.stopBubbleStream = stopBubbleStream;
window.clearAllBubbles = clearAllBubbles;

